const EdgeInsets.all(10),                child: Column(                  crossAxisAlignment: CrossAxisAlignment.start,                  children: [                    widget.isCommonMessageOrStudentReport == 0 ? Column(                      crossAxisAlignment: CrossAxisAlignment.start,                      children: [                        Text("asClass".tr,style: labelTextStyle,),                        const SizedBox(                          height: 10,                        ),                        Container(                          width: MediaQuery.of(context).size.width,                          height: 60,                          padding: const EdgeInsets.all(20),                          decoration: BoxDecoration(                              borderRadius: BorderRadius.circular(5),                              color: AppColors.primary.withOpacity(0.05)                          ),                          child: DropdownButton<Datum>(                            isExpanded: true,                            value: selectedClass,                            underline: const SizedBox(),                            icon: const Icon(Icons.arrow_drop_down_sharp),                            items: classList.map<DropdownMenuItem<Datum>>((Datum e){                              return DropdownMenuItem<Datum>(value: e,child: Text(e.cName,style: labelTextStyle.copyWith(fontWeight: FontWeight.w500,color: AppColors.secondary.withOpacity(0.4)),),);                            }).toList(), onChanged: (Datum? value) {                            setState(() {                              selectedClass = value!;                            });                            if(selectOption == SelectOption.selected){                              setState(() {                                isLoading = true;                              });                              getStudentList(value!.cid);                            }                          },                          ),                        ),                        const SizedBox(height: 10,),                        Text("asParent".tr,style: labelTextStyle,),                        Row(                          mainAxisAlignment: MainAxisAlignment.start,                          children: [                            Radio(                              value: SelectOption.all,                              groupValue: selectOption,                              onChanged: (SelectOption? val) {                                setState(() {                                  selectOption = val;                                });                              },                              activeColor: AppColors.primary,                            ),                            Text("asAll".tr,style: labelTextStyle.copyWith(fontSize: 14),)                          ],                        ),                        Row(                          mainAxisAlignment: MainAxisAlignment.start,                          children: [                            Radio(                              value: SelectOption.selected,                              groupValue: selectOption,                              onChanged: (SelectOption? val) {                                setState(() {                                  selectOption = val;                                });                                if(selectOption == SelectOption.selected && selectedClass.cid != "igex404"){                                  setState(() {                                    isLoading = true;                                  });                                  getStudentList(selectedClass.cid);                                }                              },                              activeColor: AppColors.primary,                            ),                            Text("asSelect".tr,style: labelTextStyle.copyWith(fontSize: 14),)  