st SizedBox(                      height: 10,                    ),                    Visibility(                        visible: widget.isCommonMessageOrStudentReport == 1,                        child: Row(                          mainAxisAlignment: MainAxisAlignment.spaceBetween,                          children: [                            Text("asRpt".tr,style: labelTextStyle,),                            GestureDetector(                              onTap: (){                                showDialog(context: context, builder: (BuildContext context){                                  return AlertDialog(                                    content: Wrap(                                      children: [                                        SizedBox(                                          height: 100,                                          child: Center(                                            child: ScrollConfiguration(                                              behavior: const ScrollBehavior().copyWith(overscroll: false),                                              child: ListView.builder(                                                  itemCount: widget.listOfParent!.length,                                                  itemBuilder: (ctx,index){                                                    TempParentModel parentDetail = widget.listOfParent![index];                                                    return Column(                                                      mainAxisAlignment: MainAxisAlignment.center,                                                      crossAxisAlignment: CrossAxisAlignment.start,                                                      children: [                                                        Text(                                                          parentDetail.name,                                                          style: const TextStyle(                      