                          margin: const EdgeInsets.only(top: 10,bottom: 10),                          decoration: BoxDecoration(                              borderRadius: BorderRadius.circular(10),                              color: AppColors.primary.withOpacity(0.05)                          ),                          padding: const EdgeInsets.only(top: 5,left: 10,right: 5,bottom: 5),                          height: 300,                          child: ScrollConfiguration(                              behavior: const ScrollBehavior().copyWith(overscroll: false),                              child: isLoading == true ? const SizedBox.shrink() : subSlotData.isEmpty ? Center(child: Text('asNoSlot'.tr,style: CustomStyle.name.copyWith(color: AppColors.secondary),),) : ListView.separated(                                itemBuilder: (context,index){                                  SubSlotData subSlotDataModel = subSlotData[index];                                  return Column(                                    children: [                                      SizedBox(                                        width: MediaQuery.of(context).size.width,                                        child: Row(                                          mainAxisAlignment: MainAxisAlignment.spaceBetween,                                          children: [                                            Text("${subSlotDataModel.begintime} - ${subSlotDataModel.endtime}\t${subSlotDataModel.subName}",                                              style: TextStyle(                                                  fontFamily: "Outfit",                                                  fontWeight: FontWeight.w400,                                                  fontSize: 15,                                                  color: AppColors.secondary.withOpacity(0.4)                                              ),),                                            Switch(                                              activeColor: AppColors.primary,                                              inactiveThumbColor: AppColors.secondary.withOpacity(0.4),                                              inactiveTrackColor: AppColors.secondary.withOpacity(0.4),                                              value: _slotValue[index], onChanged: (x){                                              setState(() {                                                _slotValue[index] = x;                                              });                                            },)                                          ],                                        ),                                      ),                                      Container(                                        decoration: BoxDecoration(                                          borderRadius: BorderRadius.circular(5),                                          color: AppColors.white,                                        ),                                        child: TextField(                                          controller: _controllers![index],                                          decoration: InputDecoration(                                            border: OutlineInputBorder(                                                borderRadius: BorderRadius.circular(5),                                                borderSide: BorderSide.none                                            ),                                          ),                                          cursorColor: AppColors.primary,                                          keyboardType: TextInputType.multiline,                                          maxLines: 2,                                        ),                                      )                                    ],                                  );                                },                                itemCount: subSlotData.length,                                separatorBuilder: (BuildContext context, int index) { return const SizedBox(height: 10,); },),                          ),                        )),                    Text("asAtch".tr,style: labelTextStyle,),                    const SizedBox(                      height: 5,                    ),                    GestureDetector(                      onTap: (){                        pickFile();                      },                      child: Container(                        width: MediaQuery.of(context).size.width,                        height: 60,                        padding: const EdgeInsets.only(left: 10),                        decoration: BoxDecoration(                            borderRadius: BorderRadius.circular(10),                            color: AppColors.primary.withOpacity(0.05)),                        child: Align(                          alignment: Alignment.centerLeft,                          child: AutoSizeText(fileName != "asChoose".tr ? fileName.split("/").last : fileName,style: labelTextStyle.copyWith(fontSize: 18,color: AppColors.secondary.withOpacity(0.4)),),                        ),                      ),                    ),                    const SizedBox(height: 20,),                    SizedBox(                      width: MediaQuery.of(context).size.width,                      height: 60,                      child: ElevatedButton(                        onPressed: () {                          // if(selectedClass.cid != "igex404" && selectOption == SelectOption.all){                          //   setState(() {                          //     isLoading = true;                          //   });                          //   // sendCommonMessage(token: "YXNzaXN0YW50MToxMjM0NTY=", classId: selectedClass.cid, subject: _subject.text, message: _message.text, isFileSelected: 0, toAllOrSelected: 0);                          // }                          if(widget.isCommonMessageOrStudentReport == 0){                            if(_subject.text.isEmpty){                            }else{                              if(selectedClass.cid != "igex404"){                                setState(() {                                  isLoading = true;                                });                                sendCommonMessage();                              }                              else{                              }                            }                          }                          else{                            if(_subject.text.isEmpty){                              Fluttertoast.showToast(msg: "please enter text");                            }else{                              setState(() {                                isLoading = true;                              });                              sendReportMessageOfStudent();                            }                          }                        },                        style: ElevatedButton.styleFrom(                            backgroundColor: AppColors.primary,                            shape: RoundedRectangleBorder(                                borderRadius: BorderRadius.circular(10)                            ),                            elevation: 0                        ),                        child: Row(                          mainAxisAlignment: MainAxisAlignment.center,                          children: [ Text("asSd".tr,style: labelTextStyle.copyWith(color: AppColors.white),),const SizedBox(width: 10,) ,const Icon(Icons.arrow_forward)],                        ),                      ),                    ),                  ],                ),              ),              Visibility(                  visible: isLoading,                  child: Container(                    width: MediaQuery.of(context).size.width,                    height: MediaQuery.of(context).size.height,                    color: Colors.black54,                    child: const Center(                      child: LoadingLayout(),                    ),                  ))            ],          ),        ),      ),    );  }  //this will pick single file from mobile.  //any type of file can be selected.  void pickFile() async{    FilePickerResult? result = await FilePicker.platform.pickFiles(      allowMultiple: false,    );    if(result == null){      Fluttertoast.showToast(msg: "");    }else{      setState(() {        fileName = result.files.single.path!;        isFileSelected = 1;      });      // File file = File(result.files.single.path);    }  }  //this will get class list  void getClassList() async{    ApiClass apiClass = ApiClass();    SessionManagement sessionManagement = SessionManagement();    Assistant assistant = await sessionManagement.getAssistantDetail();    String token = assistant.basicAuthToken;    dynamic tempChildList = await apiClass.getAsClassList(token,assistant.userdata.data.cookie ?? "");    if(tempChildList['status']){      ClassListModel classListModel = ClassListModel.fromJson(tempChildList);      List<Datum> tempClassList = [selectedClass];      tempClassList.addAll(classListModel.data ?? []);      setState(() {        classList = tempClassList;        isLoading = false;      });    }else{      setState(() {        isLoading = false;      });    }  }  //this will get student list according to selected class  void getStudentList(String id) async{    ApiClass apiclass = ApiClass();    SessionManagement sessionManagement = SessionManagement();    Assistant assistant = await sessionManagement.getAssistantDetail();    String token = assistant.basicAuthToken;    dynamic tempChildList = await apiclass.getStudentListForCommonMessage(token, id,assistant.userdata.data.cookie ?? "");    if(tempChildList['status']){      StudentListModel studentListModel = StudentListModel.fromJson(tempChildList);      List<StudentDataDatum> tempStudentList = [];      tempStudentList.addAll(studentListModel.data);      setState(() {        studentDataList = tempStudentList;        isLoading = false;      });    }else{      List<StudentDataDatum> tempStudentList = [];      tempStudentList.add(StudentDataDatum(wpUsrId: "igex12", studentName: 'asNoStd'.tr));      setState(() {        studentDataList = tempStudentList;        isLoading = false;      });    }  }  //this will get subslot list  void getSubSlotList() async{    ApiClass apiClass = ApiClass();    SessionManagement sessionManagement = SessionManagement();    Assistant assistant = await sessionManagement.getAssistantDetail();    String token = assistant.basicAuthToken;    dynamic response = await apiClass.getSubSlotList(token,widget.classId!,getDay(),assistant.userdata.data.cookie ?? "");    if(response['status']){      SubSlotModel subSlotModel = SubSlotModel.fromJson(response);      setState(() {        subSlotData = subSlotModel.data;        _slotValue = List.generate(subSlotData.length, (index) => false);        _controllers  = List.generate(subSlotData.length, (index) => TextEditingController());        isLoading = false;      });    }else{      // Failed failed = Failed.fromJson(response);      setState(() {        isLoading = false;      });    }  }    //this will send report message  void sendReportMessageOfStudent() async{    ApiClass apiClass = ApiClass();    SessionManagement sessionManagement = SessionManagement();    Assistant assistant = await sessionManagement.getAssistantDetail();    String token = assistant.basicAuthToken;    String senderId = assistant.userdata.data.id;    dynamic res = await apiClass.sendStudentReport(token: token, senderId: senderId, studentId: widget.studentId!, slotValue: _slotValue, controller: _controllers, subSlotData: subSlotData, subject: _subject.text, message: _message.text, day: getDay().toString(), attachment:isFileSelected == 0 ? "" : fileName, cookie: assistant.userdata.data.cookie ?? "");    if(res['status']){      Fluttertoast.showToast(msg: 'assistantToParent'.tr);      setState(() {        isLoading = false;      });     back();    }    else{      Fluttertoast.showToast(msg: res['message']);      setState(() {        isLoading = false;      });    }  }  //this will send common message.  void sendCommonMessage() async{      ApiClass apiClass = ApiClass();      SessionManagement sessionManagement = SessionManagement();      Assistant assistant = await sessionManagement.getAssistantDetail();      String token = assistant.basicAuthToken;      String senderId = assistant.userdata.data.id;      if(isFileSelected == 0){        //common message send without attachment.        Map<String,dynamic> bodyData = formBodyDataOfCommonMessage(senderId: senderId );        dynamic res  = await apiClass.sendCommonMessageWithOutAttachment(bodyData, token,assistant.userdata.data.cookie ?? "");        if(res['status']){          Fluttertoast.showToast(msg:'parentSendMessage'.tr);          setState(() {            isLoading = false;          });          back();        }        else{          setState(() {            isLoading = false;          });        }      }else{        //common message send with attachment.        if(selectOption == SelectOption.all){          //to all parent          dynamic res = await apiClass.sendCommonMessageWithAttachment(token: token, senderId: senderId, subject: _subject.text, message: _message.text, attachment: fileName,toAllOrParent: 0,classId: selectedClass.cid, cookie: assistant.userdata.data.cookie ?? "");          if(res['status']){            setState(() {              isLoading = false;            });            Fluttertoast.showToast(msg: 'parentSendMessage'.tr);            back();          }          else{            setState(() {              isLoading = false;            });            Fluttertoast.showToast(msg: res['Message']);          }        }else{          //selected student parent          dynamic res = await apiClass.sendCommonMessageWithAttachment(token: token, senderId: senderId, subject: _subject.text, message: _message.text, attachment: fileName,toAllOrParent: 1,receiverId: selectStudentList, cookie: assistant.userdata.data.cookie ?? "");          if(res['status']){            setState(() {              isLoading = false;            });            Fluttertoast.showToast(msg: 'parentSendMessage'.tr);            back();          }          else{            setState(() {              isLoading = false;            });            Fluttertoast.showToast(msg: res['Message']);          }        }     }  }    void back() {      Navigator.pushAndRemoveUntil(context, MaterialPageRoute(builder: (context)=> const AssistantScreen(currentIndex: 0,)), (route) => false);  }  Map<String, dynamic> formBodyDataOfCommonMessage({required String senderId}) {    // 0 : toAll    // 1 : selected    Map<String,dynamic> tempMap = {};    tempMap['sender_id'] = senderId;    if(selectOption == SelectOption.all){      tempMap['classid'] = selectedClass.cid;    }else{      for(int i=0;i<selectStudentList.length;i++){        tempMap["reciever_id[$i]"] = selectStudentList[i];      }    }    tempMap['subject'] = _subject.text;    tempMap['msg'] = _message.text;    tempMap['attachment'] = fileName;    return tempMap;  }   int getDay() {    //for monday it will 1    return DateTime.now().weekday;  }}